[Generator]
public class MapperGenerator : IIncrementalGenerator
{
    public void Initialize(IncrementalGeneratorInitializationContext ctx)
    {
        var mapperDecls = ctx.SyntaxProvider
            .ForAttributeWithMetadataName(
                "MyLib.GenerateMapperAttribute",
                predicate: (node, _) => node is ClassDeclarationSyntax,
                transform: (ctx, _) => GetMapperInfo(ctx))
            .Where(x => x is not null);

        ctx.RegisterSourceOutput(mapperDecls, (spc, info) =>
        {
            var source = GenerateMapper(info!);
            spc.AddSource($"{info!.ClassName}.g.cs", source);
        });
    }
}

